mapper.select:
SELECT DISTINCT CAFE_ID, CAFE_NAME
FROM VW_CAFE_ROOM_INFO
WHERE CAFE_OWNER = #{userId} OR CAFE_MANAGER= #{userId}

SELECT RO.RES_OPEN_ID , R.CAFE_ID, C.CAFE_NAME , RO.ROOM_ID, R.ROOM_NAME , TO_CHAR(RO.OPEN_AT, 'YYYY-MM-DD HH24:MI') AS OPEN_AT , TO_CHAR(RO.OPEN_AT, 'YYYY-MM-DD') AS OPEN_DATE , TO_CHAR(RO.OPEN_AT, 'HH24:MI') AS OPEN_TIME FROM RES_OPEN RO JOIN ROOM R ON RO.ROOM_ID = R.ROOM_ID JOIN CAFE C ON R.CAFE_ID = C.CAFE_ID
R.CAFE_ID IN( SELECT DISTINCT CAFE_ID FROM VW_CAFE_ROOM_INFO WHERE CAFE_OWNER = #{userId} OR CAFE_MANAGER= #{userId} ) AND RO.RES_OPEN_ID NOT IN (SELECT RES_OPEN_ID FROM RES_DROP) AND TO_CHAR(RO.OPEN_AT, 'YYYY-MM-DD') = #{schDate}
AND R.CAFE_ID = #{schCafe}
